from flask import Flask, session, redirect, url_for, request
from redis import Redis
import functools
import json

app = Flask(__name__)
app.secret_key = 'your_secret_key'
redis = Redis(host='localhost', port=6379, db=0)

def cache(expire=60):
    def decorator(f):
        @functools.wraps(f)
        def wrapped(*args, **kwargs):
            cache_key = f'cache:{args}:{kwargs}'
            cached_result = redis.get(cache_key)
            if cached_result:
                return json.loads(cached_result)
            result = f(*args, **kwargs)
            redis.setex(cache_key, expire, json.dumps(result))
            return result
        return wrapped
    return decorator

@app.route('/')
def index():
    return 'Welcome to the Flask Redis App!'

@app.route('/login', methods=['POST'])
def login():
    username = request.form['username']
    session['user'] = username
    redis.set(f'session:{session.sid}', json.dumps(session), ex=3600)
    return redirect(url_for('index'))

@app.route('/protected')
def protected():
    user_session = redis.get(f'session:{session.sid}')
    if user_session:
        session_data = json.loads(user_session)
        return f'Hello, {session_data["user"]}!'
    return 'You are not logged in!'

